import React, { useState, useEffect } from 'react';
// Thay đổi dòng import cũ của bạn:
import { List, ListItem, ListItemText, Typography, Divider } from '@mui/material'; 
// Đảm bảo có chữ "Divider" ở đây ^^^
import { useParams, Link } from 'react-router-dom';
import fetchModel from '../../lib/fetchModelData';

function UserDetail() {
  const { userId } = useParams(); // Lấy ID từ URL (ví dụ: /users/64b1f...)
  const [user, setUser] = useState(null);

  useEffect(() => {
    // Gọi API chi tiết người dùng
    fetchModel(`/user/${userId}`)
      .then((response) => {
        setUser(response.data);
      })
      .catch((err) => console.log("Lỗi khi tải chi tiết người dùng:", err));
  }, [userId]); // Chạy lại mỗi khi userId thay đổi

  if (!user) return <Typography>Đang tải dữ liệu...</Typography>;

  return (
    <Paper elevation={3} sx={{ p: 3 }}>
      <Typography variant="h4">{`${user.first_name} ${user.last_name}`}</Typography>
      <Divider sx={{ my: 2 }} />

      <Box sx={{ mb: 2 }}>
        <Typography variant="subtitle1">**Nghề nghiệp:** {user.occupation}</Typography>
        <Typography variant="subtitle1">**Địa điểm:** {user.location}</Typography>
      </Box>

      <Typography variant="body1" sx={{ mb: 3 }}>
        **Mô tả:** {user.description}
      </Typography>

      <Button 
        variant="contained" 
        component={Link} 
        to={`/photos/${userId}`}
      >
        Xem ảnh của {user.first_name}
      </Button>
    </Paper>
  );
}

export default UserDetail;
